# Memoize results keyed by (action, history_hash) to avoid re-executing
# actions we've already tried in an identical context.
import hashlib

def history_hash(history: list[dict]) -> str:
    key = str([(h['action'], str(h['result'])[:50]) for h in history])
    return hashlib.md5(key.encode()).hexdigest()

class MemoizedBacktrackingAgent(BacktrackingAgent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self._cache: dict[str, dict] = {}  # (action, hist_hash) -> result

    def execute_or_cached(
        self,
        action: str,
        execute_fn,
    ) -> dict:
        key = f'{action}:{history_hash(self._history)}'
        if key in self._cache:
            return self._cache[key]  # replay without calling the tool again
        result = execute_fn(action)
        self._cache[key] = result
        return result

# Integrating backtracking with the planning loop:
# The planner emits alternatives; the executor detects dead ends;
# the backtracking agent connects them.

def run_full_example(
    goal: str = 'Find the latest quarterly revenue figures for Acme Corp',
):
    import anthropic
    client = anthropic.Anthropic()

    def mock_execute(action: str) -> dict:
        # Simulate: web search succeeds, SEC EDGAR times out
        if 'EDGAR' in action:
            return {'status': 'timeout', 'result': None}
        if 'web_search' in action:
            return {'status': 'success', 'result': 'Revenue: $4.2B (Q3 2024)'}
        return {'status': 'empty', 'result': None}

    def is_dead_end(result: dict) -> bool:
        return result.get('status') in ('timeout', 'empty', 'error')

    history = run_with_backtracking(
        client=client,
        goal=goal,
        execute_fn=mock_execute,
        is_dead_end_fn=is_dead_end,
        max_steps=10,
        max_backtracks=3,
    )
    for entry in history:
        print(f"Step {entry['step']}: {entry['action']} -> {entry['result']['status']}")
    return history
